require_once __DIR__.'/../config.php';require_once __DIR__.'/../lib/layout.php';require_once __DIR__.'/../lib/retail_analytics.php';requiere_roles(['ADMIN','TI','GERENCIA','CEO','DIRECTOR','ANALISTA'],'../');$pdo=db();$actor=usuario_actual();$msg=null;
if($_SERVER['REQUEST_METHOD']==='POST'){try{$accion=$_POST['accion']??'';if($accion==='importar'){if(!tiene_rol(['ADMIN','TI','ANALISTA']))throw new RuntimeException('Solo TI, Administración o Analítica puede importar.');if(empty($_FILES['archivo']['tmp_name'])||!is_uploaded_file($_FILES['archivo']['tmp_name']))throw new RuntimeException('Selecciona un archivo.');if((int)$_FILES['archivo']['size']>20*1024*1024)throw new RuntimeException('El archivo supera 20 MB.');$nombre=basename((string)$_FILES['archivo']['name']);$ext=strtolower(pathinfo($nombre,PATHINFO_EXTENSION));if(!in_array($ext,['csv','xlsx'],true))throw new RuntimeException('Solo se admiten CSV y XLSX.');$r=retail_importar_archivo($pdo,$_FILES['archivo']['tmp_name'],$nombre,(string)($_POST['tipo_csv']??''),$actor);$msg=$r['duplicada']?['error','Ese archivo ya fue procesado; no se duplicaron datos.']:['ok',"Importación completa: {$r['importadas']} filas aceptadas y {$r['errores']} con observaciones."];}elseif($accion==='configurar'){if(!tiene_rol(['ADMIN','TI']))throw new RuntimeException('Solo TI o Administración puede cambiar los umbrales.');$s=$pdo->prepare("INSERT INTO config_general(clave,valor)VALUES(?,?) ON CONFLICT(clave)DO UPDATE SET valor=excluded.valor");$s->execute(['RETAIL_LEAD_TIME_DIAS',(string)min(90,max(1,(int)$_POST['lead_time']))]);$s->execute(['RETAIL_SOBRESTOCK_DIAS',(string)min(365,max(15,(int)$_POST['sobrestock']))]);$msg=['ok','Umbrales actualizados.'];}}catch(Throwable $e){$msg=['error',$e->getMessage()];}}
$sede=trim((string)($_GET['sede']??''));$a=retail_analitica($pdo,$sede?:null);$sedes=$pdo->query('SELECT DISTINCT sede_codigo,sede_nombre FROM retail_existencias ORDER BY sede_nombre')->fetchAll(PDO::FETCH_ASSOC);$imports=$pdo->query('SELECT * FROM retail_importaciones ORDER BY id DESC LIMIT 12')->fetchAll(PDO::FETCH_ASSOC);$errores=$pdo->query('SELECT e.*,i.archivo FROM retail_importacion_errores e JOIN retail_importaciones i ON i.id=e.importacion_id ORDER BY e.id DESC LIMIT 15')->fetchAll(PDO::FETCH_ASSOC);$m=$a['metricas'];layout_inicio('Inventario Retail','Inventario Retail','../');?>
<div class="page-kicker">FASE 7 · ROTACIÓN, COBERTURA Y TALLAS</div><h1><?=icon('inventory','icon-lg')?> Inventario Retail</h1><p class="subtitle">Lectura comercial basada en exportaciones reales de Siesa. Fecha de corte: <?=e($a['corte']??'sin datos cargados')?>.</p><?php if($msg):?><div class="msg-<?=e($msg[0])?>"><?=e($msg[1])?></div><?php endif;?>
<?php if(!$a['corte']):?><section class="retail-empty"><span class="page-kicker">FUENTE PENDIENTE</span><h2>Conectemos ventas y existencias, no supuestos.</h2><p>Los archivos de TI revisados no contienen movimientos comerciales. Exporta desde Siesa productos, existencias y ventas, o envíalos desde n8n a la API firmada.</p><div class="toolbar"><a class="btn btn-secondary" href="retail_plantilla.php?tipo=PRODUCTOS">Plantilla productos</a><a class="btn btn-secondary" href="retail_plantilla.php?tipo=EXISTENCIAS">Plantilla existencias</a><a class="btn btn-secondary" href="retail_plantilla.php?tipo=VENTAS">Plantilla ventas</a></div></section><?php endif;?>
<section class="retail-hero"><div><span>VENTA NETA · 28 DÍAS</span><strong>$<?=number_format((float)$m['valor_28d'],0,',','.')?></strong><p><?=number_format((float)$m['ventas_28d'],0,',','.')?> unidades · <?=number_format((float)$m['stock'],0,',','.')?> unidades disponibles</p></div><div class="retail-risk"><strong><?=(int)$m['quiebres']?></strong><span>quiebres</span><strong><?=(int)$m['riesgos']?></strong><span>en riesgo</span></div></section>
<div class="cards"><div class="card <?=$m['quiebres']?'card-err':'card-ok'?>"><div class="num"><?=(int)$m['quiebres']?></div><div class="label">Quiebres con venta</div></div><div class="card <?=$m['riesgos']?'card-warn':'card-ok'?>"><div class="num"><?=(int)$m['riesgos']?></div><div class="label">Cobertura menor a <?=$a['lead_time']??14?> días</div></div><div class="card <?=$m['huecos_talla']?'card-warn':'card-ok'?>"><div class="num"><?=(int)$m['huecos_talla']?></div><div class="label">Huecos de talla</div></div><div class="card"><div class="num"><?=(int)$m['sobrestock']?></div><div class="label">Sin rotación / sobrestock</div></div><div class="card"><div class="num"><?=count($a['filas'])?></div><div class="label">SKU · tienda analizados</div></div></div>
<div class="panel-grid-2"><section class="panel"><h3>Cargar exportación Siesa</h3><form method="post" enctype="multipart/form-data"><input type="hidden" name="accion" value="importar"><label>Archivo CSV o XLSX · máximo 20 MB</label><input type="file" name="archivo" accept=".csv,.xlsx" required><label>Si es CSV, contenido</label><select name="tipo_csv"><option value="VENTAS">Ventas</option><option value="EXISTENCIAS">Existencias</option><option value="PRODUCTOS">Productos</option></select><button style="margin-top:12px">Importar y validar</button></form><p class="small">En XLSX se reconocen las hojas PRODUCTOS, EXISTENCIAS y VENTAS. Un checksum evita cargar dos veces el mismo archivo.</p></section><section class="panel"><h3>Reglas de cobertura</h3><form method="post"><input type="hidden" name="accion" value="configurar"><div class="grid-form"><div><label>Lead time (días)</label><input type="number" name="lead_time" value="<?=$a['lead_time']??14?>"></div><div><label>Sobrestock desde (días)</label><input type="number" name="sobrestock" value="<?=$a['sobrestock_dias']??60?>"></div></div><button>Guardar umbrales</button></form><p class="small">Cobertura = existencia actual ÷ venta diaria de los últimos 28 días. No se presenta como pronóstico hasta contar con histórico suficiente.</p></section></div>
<section class="panel"><div class="approval-heading"><div><span class="page-kicker">OPORTUNIDADES POR SKU Y TIENDA</span><h2>Cobertura actual</h2></div><form method="get"><select name="sede" onchange="this.form.submit()"><option value="">Todas las tiendas</option><?php foreach($sedes as $s):?><option value="<?=e($s['sede_codigo'])?>" <?=$sede===$s['sede_codigo']?'selected':''?>><?=e($s['sede_nombre']?:$s['sede_codigo'])?></option><?php endforeach;?></select></form></div><div class="table-scroll"><table><thead><tr><th>Referencia / variante</th><th>Tienda</th><th>Stock</th><th>Venta 28d</th><th>Cobertura</th><th>Sell-through</th><th>Estado</th></tr></thead><tbody><?php foreach(array_slice($a['filas'],0,150) as $f):?><tr><td><strong><?=e($f['referencia']?:$f['sku'])?></strong><br><span class="small"><?=e(trim(($f['color']??'').' · '.($f['talla']??''),' ·'))?> · <?=e($f['sku'])?></span></td><td><?=e($f['sede_nombre']?:$f['sede_codigo'])?></td><td><?=number_format((float)$f['stock'],0,',','.')?></td><td><?=number_format((float)$f['ventas_28d'],0,',','.')?></td><td><?=$f['cobertura_dias']===null?'—':number_format((float)$f['cobertura_dias'],1,',','.').' d'?></td><td><?=number_format((float)$f['sell_through']*100,0)?>%</td><td><span class="badge retail-status-<?=strtolower($f['estado'])?>"><?=e($f['estado'])?></span></td></tr><?php endforeach;?><?php if(!$a['filas']):?><tr><td colspan="7" class="small">Carga al menos una fotografía de existencias. Las ventas completarán el cálculo de cobertura.</td></tr><?php endif;?></tbody></table></div></section>
<div class="panel-grid-2"><section class="panel"><h3>Importaciones</h3><table><thead><tr><th>Archivo</th><th>Resultado</th><th>Filas</th></tr></thead><tbody><?php foreach($imports as $i):?><tr><td><?=e($i['archivo'])?><br><span class="small"><?=e($i['creado_en'])?></span></td><td><span class="badge badge-otro"><?=e($i['estado'])?></span></td><td><?=(int)$i['filas_importadas']?> / <?=(int)$i['filas_leidas']?></td></tr><?php endforeach;?><?php if(!$imports):?><tr><td colspan="3" class="small">Sin importaciones comerciales.</td></tr><?php endif;?></tbody></table></section><section class="panel"><h3>Calidad de datos</h3><table><thead><tr><th>Archivo / fila</th><th>Observación</th></tr></thead><tbody><?php foreach($errores as $e):?><tr><td><?=e($e['archivo'])?> · <?=$e['fila']?></td><td><?=e($e['motivo'])?></td></tr><?php endforeach;?><?php if(!$errores):?><tr><td colspan="2" class="small">No hay errores de calidad registrados.</td></tr><?php endif;?></tbody></table></section></div>
<?php layout_fin();?>
